package com.izonehub.stores.user;import com.izonehub.stores.auth.PasswordPolicy;import org.junit.jupiter.api.Test;import org.springframework.security.crypto.argon2.Argon2PasswordEncoder;import static org.assertj.core.api.Assertions.*;import static org.mockito.Mockito.*;class UserCommandServiceTest{@Test void refusesCreatingSystemAdministrator(){UserRepository repo=mock(UserRepository.class);UserCommandService svc=new UserCommandService(repo,Argon2PasswordEncoder.defaultsForSpringSecurity_v5_8(),new PasswordPolicy());assertThatThrownBy(()->svc.createUser("Admin","a@example.com","Password1!",Role.SYSTEM_ADMINISTRATOR,null,null)).isInstanceOf(IllegalArgumentException.class);verify(repo,never()).save(any());}}
